function formatDateWithOrdinal(isoDate, locale = 'en-US') {
  const d = new Date(isoDate);
  if (Number.isNaN(d.getTime())) throw new Error('Invalid date string');

  const month = d.toLocaleString(locale, { month: 'long' });
  const day = d.getDate();

  // Ordinal suffix rules
  const suffix = (n => {
    const rem100 = n % 100;
    if (rem100 >= 11 && rem100 <= 13) return 'th';
    switch (n % 10) {
      case 1: return 'st';
      case 2: return 'nd';
      case 3: return 'rd';
      default: return 'th';
    }
  })(day);

  return `${month} ${day}${suffix}`;
}

/**
 * Convert max_days to integer and ensure it doesn't exceed 30
 * @param {any} maxDays - The max days value (can be string, number, or any type)
 * @returns {number} Integer value capped at 30
 */
function normalizeMaxDays(maxDays) {
    let days;

    // If it's a string, try to extract digits first
    if (typeof maxDays === 'string') {
        // Extract first number from string (e.g., "3 days" → "3")
        const match = maxDays.match(/\d+/);
        if (match) {
            days = parseInt(match[0]);
        } else {
            days = NaN; // No digits found
        }
    } else {
        // Convert to integer directly
        days = parseInt(maxDays);
    }

    // Handle invalid values (NaN, null, undefined, etc.)
    if (isNaN(days) || days <= 0) {
        days = 30; // Default to 30 if invalid
    }

    // Cap at 30 days maximum
    if (days > 30) {
        days = 30;
    }

    return days;
}

