function filterSlots(slots, specificTime = null, timeGapMinutes = 60, hourlyIntervalMinutes = 60) {
    if (!slots || !Array.isArray(slots) || slots.length === 0) {
        return [];
    }

    // If fewer than 5 slots, return all without filtering
    if (slots.length < 5) {
        return slots;
    }

    // Case 1: Filter around specific time    
    if (specificTime) {
        const targetTime = parseTimeString(specificTime);
        if (targetTime) {
            const timeFilteredSlots = filterAroundSpecificTime(slots, targetTime, timeGapMinutes);
            //apply 30-minute interval filtering to the results
            return filterByHourlyInterval(timeFilteredSlots, 60, targetTime);
        }
    }

    // Case 2: Filter by hourly intervals
    return filterByHourlyInterval(slots, hourlyIntervalMinutes);
}

/**
 * Filter slots around a specific time with configurable gap
 */
function filterAroundSpecificTime(slots, targetTime, gapMinutes) {

   const filteredSlots = slots.filter(slot => {
        const slotTime = new Date(slot.start_date);

        // Convert UTC time to local timezone
        const localTimeString = slotTime.toLocaleString("en-US", { 
            timeZone: timezone,
            hour12: false,
            hour: '2-digit',
            minute: '2-digit'
        });

        // Parse the local time string "HH:MM"
        const [slotHour, slotMinute] = localTimeString.split(':').map(Number);

        // Convert times to minutes for easier comparison
        const targetTotalMinutes = targetTime.hour * 60 + targetTime.minute;
        const slotTotalMinutes = slotHour * 60 + slotMinute;

        // Simple time difference check (no cross-day logic needed)
        const timeDifference = Math.abs(slotTotalMinutes - targetTotalMinutes);

        return timeDifference <= gapMinutes;
    });

    // If no slots found after filtering, return original slots
    return filteredSlots.length > 0 ? filteredSlots : slots;
}

function filterByHourlyInterval(slots, intervalMinutes, targetTime = null) {
    if (slots.length === 0) return [];

    // Group slots by date to process each day independently
    const slotsByDate = {};

    slots.forEach(slot => {
        const slotTime = new Date(slot.start_date);
        const dateKey = slotTime.toLocaleString("en-US", { 
            timeZone: timezone,
            year: 'numeric',
            month: '2-digit',
            day: '2-digit'
        });

        if (!slotsByDate[dateKey]) {
            slotsByDate[dateKey] = [];
        }
        slotsByDate[dateKey].push(slot);
    });

    const filteredSlots = [];

    // Process each date independently
    Object.keys(slotsByDate).forEach(dateKey => {
        const dateSlotsGroup = slotsByDate[dateKey];
        let referenceTime = null;

        // If we have a target time, use it as the reference point
        if (targetTime) {
            referenceTime = targetTime.hour * 60 + targetTime.minute;
        }

        dateSlotsGroup.forEach(slot => {
            // Convert UTC to local time for proper interval calculation
            const slotTime = new Date(slot.start_date);
            const localTimeString = slotTime.toLocaleString("en-US", { 
                timeZone: timezone,
                hour12: false,
                hour: '2-digit',
                minute: '2-digit'
            });

            const [slotHour, slotMinute] = localTimeString.split(':').map(Number);
            const slotTotalMinutes = slotHour * 60 + slotMinute;

            if (referenceTime === null) {
                // If no target time, use the first slot of this date as reference
                filteredSlots.push(slot);
                referenceTime = slotTotalMinutes;
            } else {
                // Calculate how far this slot is from our reference intervals
                const timeSinceReference = slotTotalMinutes - referenceTime;
                const intervalNumber = Math.round(timeSinceReference / intervalMinutes);
                const expectedTime = referenceTime + (intervalNumber * intervalMinutes);
                const timeFromExpected = Math.abs(slotTotalMinutes - expectedTime);

                // Check if this slot is close to an expected interval time
                if (intervalNumber >= 0 && timeFromExpected < 5) { // Allow 5 minute tolerance
                    filteredSlots.push(slot);
                } 
            }
        });
    });

    // If no filtered slots found, return original slots
    return filteredSlots.length > 0 ? filteredSlots : slots;
}

/**
 * Parse time string to hour and minute
 */
function parseTimeString(timeStr) {
    // Handle formats like "3:15 PM", "15:15", "3:15"
    const time12HourMatch = timeStr.match(/(\d{1,2}):(\d{2})\s*(AM|PM)/i);
    const time24HourMatch = timeStr.match(/(\d{1,2}):(\d{2})/);

    if (time12HourMatch) {
        let hour = parseInt(time12HourMatch[1]);
        const minute = parseInt(time12HourMatch[2]);
        const period = time12HourMatch[3].toUpperCase();

        if (period === 'PM' && hour !== 12) hour += 12;
        if (period === 'AM' && hour === 12) hour = 0;

        return { hour, minute };
    } else if (time24HourMatch) {
        const hour = parseInt(time24HourMatch[1]);
        const minute = parseInt(time24HourMatch[2]);
        return { hour, minute };
    }

    return null;
}

